SELECT COUNT(*) AS active_series_count, COUNT(DISTINCT geography) AS distinct_geographies_count
FROM data_series
WHERE is_active = 1;

SELECT title
FROM data_series
WHERE series_id = '0';

SELECT title
FROM data_series
ORDER BY title;

SELECT COUNT(dp.point_id) AS total_annotated_data_points
FROM data_points dp
JOIN data_annotations da ON dp.point_id = da.point_id;
